const GC_G82_SD_IMG = "data:image/png;base64,";
const GC_G82_HD_IMG = "data:image/png;base64,";
const GC_G52_SD_IMG = "data:image/png;base64,";
const GC_G52_HD_IMG = "data:image/png;base64,";
const GC_G20_SD_IMG = "data:image/png;base64,";
const GC_G20_HD_IMG = "data:image/png;base64,";

// Map resolved style code -> image
const GC_ASSEMBLY_IMAGES = {
  'G20-SD': GC_G20_SD_IMG,
  'G20-HD': GC_G20_HD_IMG,
  'G52-SD': GC_G52_SD_IMG,
  'G52-HD': GC_G52_HD_IMG,
  'G82-SD': GC_G82_SD_IMG,
  'G82-HD': GC_G82_HD_IMG,
  // Shrouded variants share exposed bolt images
  'G10-SD': GC_G20_SD_IMG,
  'G10-HD': GC_G20_HD_IMG,
  'G51-SD': GC_G52_SD_IMG,
  'G51-HD': GC_G52_HD_IMG,
  'G81-SD': GC_G82_SD_IMG,
  'G81-HD': GC_G82_HD_IMG,
};

function gcGetAssemblyImage(style) {
  return GC_ASSEMBLY_IMAGES[style] || null;
}
